SELECT
    SUM(CASE WHEN LOWER(categoria) LIKE '%rotação de culturas%' THEN 1 ELSE 0 END) AS estabelecimentos_rotação_culturas,
    SUM(CASE WHEN LOWER(categoria) LIKE '%rotação de culturas%' AND LOWER(unidade) = 'hectares' THEN valor ELSE 0 END) AS area_rotação_culturas
FROM ibge_censo_praticas_agricolas;

SELECT 'Rotação de culturas é mais exigente porque exige diversificação de culturas para prevenir degradação do solo, melhorar a fertilidade e reduzir pragas/doenças, enquanto sucessão soja–milho safrinha no plantio direto depende apenas de manejo superficial do solo e pode não oferecer os mesmos benefícios ecológicos.' AS resposta_rotacao_exigente;
